}

const DEPT_THEME: Record<string, string> = {
  Product: 'bg-[#ffe8c8] text-[#8d5e1f]',
  Engineering: 'bg-[#d2f0d8] text-[#25683a]',
  'Research Lab': 'bg-[#cfeafd] text-[#285f84]',
}

const RANK_THEME: Record<string, string> = {
