  assigned_to?: string
  routing_reasoning?: string
  dispatch_error?: string
}

type Channel = {
  id: string
  name: string
  type: 'org' | 'team' | 'direct'
  messageCount?: number
  lastActivity?: string
  participants?: string[]
}

type ChatMessage = {
  id: string
  channel: string
  from: string
  text: string
  replyTo: string | null
  mentions: string[]
  ts: string
}

type LogLine = {
  id: number
  agentId: string
  missionId: string
