import { useEffect, useRef, useState } from 'react'
import { useWebSocket } from './hooks/useWebSocket'

type Agent = {
  id: string
  title: string
  department: string
  description: string
  status: 'idle' | 'running' | 'error'
  reports_to?: string
  subordinates?: string[]
  rank?: string
