                <div className="panel animate-rise p-4">
                  {/* Chairman root */}
                  <div className="flex items-center gap-2 rounded-xl border border-[#d4c9a8] bg-[#fdf8ec] px-4 py-3">
                    <span className="h-3 w-3 rounded-full bg-[#d4aa4f]" />
