import { useEffect, useRef, useState } from 'react'
import { useWebSocket } from './hooks/useWebSocket'

type Agent = {
  id: string
  title: string
  department: string
  description: string
  status: 'idle' | 'running' | 'error'
  reports_to?: string
  subordinates?: string[]
  rank?: string
  team?: string
}

type Team = {
  id: string
  name: string
  executive_sponsor: string
  head: string
  members: string[]
}

type Mission = {
  id: string
  title: string
  type: 'engineering' | 'research'
  status: string
  current_stage: string
  assignee: string | null
  workspace: string | null
  sessions: Record<string, string>
  parent_mission?: string
}

type Message = {
  id: string
  from: string
  to: string
  missionId: string
  type: 'escalate' | 'report'
  question: string | null
  context: string | null
  summary: string | null
  artifacts: string[] | null
  status: 'pending' | 'answered' | 'done'
  answer: string | null
  created_at: string
}

type Task = {
  id: string
  title: string
  status: string
  created_at: string
  feedback: Array<{ text: string; at: string }>
  mission_id?: string
  assigned_to?: string
  routing_reasoning?: string
  dispatch_error?: string
}

type Channel = {
  id: string
  name: string
  type: 'org' | 'team' | 'direct'
  messageCount?: number
  lastActivity?: string
  participants?: string[]
}

type ChatMessage = {
  id: string
  channel: string
  from: string
  text: string
  replyTo: string | null
  mentions: string[]
  ts: string
}

type LogLine = {
  id: number
  agentId: string
  missionId: string
  text: string
  kind: 'output' | 'error' | 'system'
}

const STAGES = ['backlog', 'analysis', 'design', 'development', 'testing', 'done']

const STAGE_LABELS: Record<string, string> = {
  backlog: 'Backlog',
  analysis: 'Analysis',
  design: 'Design',
  development: 'Build',
  testing: 'QA',
  done: 'Done',
}

const STAGE_THEME: Record<string, { lane: string; badge: string; empty: string }> = {
  backlog: {
    lane: 'border-[#f0d4bf] bg-[#fff4ea]',
    badge: 'bg-[#ffd8b8] text-[#9b5824]',
    empty: 'text-[#ad7b56] border-[#efc8a6] bg-[#fff0e0]',
  },
  analysis: {
    lane: 'border-[#c9e7cd] bg-[#edfef0]',
    badge: 'bg-[#c9f0ce] text-[#2f7a41]',
    empty: 'text-[#598468] border-[#badfbe] bg-[#e9faeb]',
  },
  design: {
    lane: 'border-[#cbe7e2] bg-[#ecfbfa]',
    badge: 'bg-[#caeff0] text-[#296f73]',
    empty: 'text-[#4f8082] border-[#bfe3e1] bg-[#e9f8f8]',
  },
  development: {
    lane: 'border-[#c7e0f2] bg-[#ecf8ff]',
    badge: 'bg-[#cae8ff] text-[#2d638f]',
    empty: 'text-[#507895] border-[#bdd9ee] bg-[#e9f4fd]',
  },
  testing: {
    lane: 'border-[#ebe0b5] bg-[#fffbea]',
    badge: 'bg-[#f8ecbc] text-[#8d7122]',
